    """获取配置值"""
    if not self._loaded:
        try:
            raw_value = config_manager.get(self.key)
            self._value = self._convert_value(raw_value)
            self._loaded = True
        except Exception as e:
            if self.default is not None:
                self._value = self.default
                self._loaded = True
